1	"use client";
2	
3	import type { ProviderSlug } from "@repo/app-providers/client";
4	import { useTRPC } from "@repo/app-trpc/react";
5	import { toast } from "@repo/ui/components/ui/sonner";
6	import { useQueryClient } from "@tanstack/react-query";
7	import { useCallback, useEffect, useRef, useState } from "react";
8	
9	interface UseOAuthPopupOptions {
10	  errorMessage?: string;
11	  messageType?: string;
12	  onSuccess?: () => void;
13	  popupWindowName?: string;
14	  provider: ProviderSlug;
15	  queryKeysToInvalidate: readonly (readonly unknown[])[];
16	}
17	
18	interface UseOAuthPopupReturn {
19	  handleConnect: () => Promise<void>;
20	  isConnecting: boolean;
21	  openCustomUrl: (
22	    buildUrl: (data: { url: string; state: string }) => string
23	  ) => Promise<void>;
24	}
25	
26	export function useOAuthPopup({
27	  provider,
28	  messageType,
29	  queryKeysToInvalidate,
30	  popupWindowName,
31	  onSuccess,
32	  errorMessage,
33	}: UseOAuthPopupOptions): UseOAuthPopupReturn {
34	  const trpc = useTRPC();
35	  const queryClient = useQueryClient();
36	
37	  const [isConnecting, setIsConnecting] = useState(false);
38	  const pollTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);
39	  const fallbackTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
40	  const successReceivedRef = useRef(false);
41	
42	  // Keep latest values in refs so the effect doesn't re-subscribe on every render
43	  const queryKeysRef = useRef(queryKeysToInvalidate);
44	  queryKeysRef.current = queryKeysToInvalidate;
45	  const onSuccessRef = useRef(onSuccess);
46	  onSuccessRef.current = onSuccess;
47	
48	  const resolvedMessageType = messageType ?? `${provider}_connected`;
49	  const resolvedWindowName = popupWindowName ?? `${provider}-install`;
50	  const capitalizedProvider =
51	    provider.charAt(0).toUpperCase() + provider.slice(1);
52	  const resolvedErrorMessage =
53	    errorMessage ??
54	    `Failed to connect to ${capitalizedProvider}. Please try again.`;
55	
56	  const invalidateAll = useCallback(() => {
57	    successReceivedRef.current = true;
58	    if (fallbackTimerRef.current) {
59	      clearTimeout(fallbackTimerRef.current);
60	      fallbackTimerRef.current = null;
61	    }
62	    for (const queryKey of queryKeysRef.current) {
63	      void queryClient.invalidateQueries({ queryKey: queryKey as unknown[] });
64	    }
65	    onSuccessRef.current?.();
66	  }, [queryClient]);
67	
68	  // Listen for OAuth completion via BroadcastChannel (primary) and postMessage (fallback)
69	  useEffect(() => {
70	    // Primary: BroadcastChannel (works regardless of window.opener / COOP)
71	    const channel = new BroadcastChannel("oauth-connections");
72	    channel.onmessage = (event: MessageEvent) => {
73	      if ((event.data as { type?: string }).type === resolvedMessageType) {
74	        invalidateAll();
75	      }
76	    };
77	
78	    // Fallback: postMessage (works if window.opener is available)
79	    const handler = (event: MessageEvent) => {
80	      if (event.origin !== window.location.origin) {
81	        return;
82	      }
83	      if ((event.data as { type?: string }).type === resolvedMessageType) {
84	        invalidateAll();
85	      }
86	    };
87	    window.addEventListener("message", handler);
88	
89	    return () => {
90	      channel.close();
91	      window.removeEventListener("message", handler);
92	      if (pollTimerRef.current) {
