import postgres from "postgres";

const sql = postgres({
  host: process.env.DATABASE_HOST,
  port: 5432,
  username: process.env.DATABASE_USERNAME,
  password: process.env.DATABASE_PASSWORD,
  database: "postgres",
  ssl: "require",
});

const tables = [
  "lightfast_gateway_backfill_runs",
  "lightfast_gateway_lifecycle_logs",
  "lightfast_gateway_tokens",
  "lightfast_gateway_webhook_deliveries",
  "lightfast_github_org_bindings",
  "lightfast_org_entity_edges",
  "lightfast_org_event_entities",
  "lightfast_org_events",
  "lightfast_org_entities",
  "lightfast_org_ingest_logs",
  "lightfast_org_integrations",
  "lightfast_org_repo_indexes",
  "lightfast_org_user_activities",
  "lightfast_org_workflow_runs",
  "lightfast_workspace_api_keys",
  "lightfast_gateway_installations",
];

for (const t of tables) {
  await sql.unsafe(`TRUNCATE TABLE ${t} CASCADE`);
  console.log("truncated", t);
}
await sql.end();
console.log("done — all tables empty");

